import { G } from '../theme';
import React, { useState, useEffect } from 'react';
import {
  Container, Typography, Box, Card, CardContent, TextField,
  Button, Chip, Divider, List, ListItem, ListItemText,
  Tab, Tabs, Alert, IconButton, LinearProgress, InputAdornment
} from '@mui/material';
import AddIcon from '@mui/icons-material/Add';
import DeleteIcon from '@mui/icons-material/Delete';
import TrendingUpIcon from '@mui/icons-material/TrendingUp';
import TrendingDownIcon from '@mui/icons-material/TrendingDown';
import AccountBalanceIcon from '@mui/icons-material/AccountBalance';
import CreditCardIcon from '@mui/icons-material/CreditCard';
import CheckCircleIcon from '@mui/icons-material/CheckCircle';
import LockIcon from '@mui/icons-material/Lock';
import LockOpenIcon from '@mui/icons-material/LockOpen';
import ShieldIcon from '@mui/icons-material/Shield';
import { useAuth } from '../context/AuthContext';

/* ─── PIN LOCK SCREEN ─────────────────────────────────── */
function PinLock({ onUnlock }) {
  const { user } = useAuth();
  const [pin, setPin] = useState('');
  const [error, setError] = useState('');
  const [shake, setShake] = useState(false);
  const [attempts, setAttempts] = useState(0);
  const [locked, setLocked] = useState(false);
  const [lockTimer, setLockTimer] = useState(0);

  useEffect(() => {
    if (locked && lockTimer > 0) {
      const t = setTimeout(() => setLockTimer(s => s - 1), 1000);
      return () => clearTimeout(t);
    }
    if (locked && lockTimer === 0) setLocked(false);
  }, [locked, lockTimer]);

  const addDigit = (d) => {
    if (locked || pin.length >= 4) return;
    const next = pin + d;
    setPin(next);
    setError('');

    if (next.length === 4) {
      setTimeout(() => {
        const correctPin = user?.pin;
        if (next === correctPin) {
          onUnlock();
        } else {
          setShake(true);
          setTimeout(() => setShake(false), 600);
          const newAttempts = attempts + 1;
          setAttempts(newAttempts);
          if (newAttempts >= 3) {
            setLocked(true);
            setLockTimer(30);
            setError(`Too many attempts. Locked for 30 seconds.`);
          } else {
            setError(`Wrong PIN. ${3 - newAttempts} attempt${3 - newAttempts === 1 ? '' : 's'} left.`);
          }
          setPin('');
        }
      }, 120);
    }
  };

  const del = () => setPin(p => p.slice(0, -1));

  return (
    <Box sx={{
      minHeight: '100vh', display: 'flex', alignItems: 'center',
      justifyContent: 'center', flexDirection: 'column', gap: 4,
    }}>
      <Box sx={{
        p: 5, borderRadius: 5, textAlign: 'center', maxWidth: 340, width: '100%', mx: 3,
        bgcolor: 'rgba(13,38,24,0.85)', backdropFilter: 'blur(24px)',
        border: '1px solid rgba(148,204,171,0.15)',
        boxShadow: '0 24px 60px rgba(0,0,0,0.5)',
        animation: shake ? 'shake 0.5s ease' : 'none',
        '@keyframes shake': {
          '0%,100%': { transform: 'translateX(0)' },
          '20%': { transform: 'translateX(-10px)' },
          '40%': { transform: 'translateX(10px)' },
          '60%': { transform: 'translateX(-8px)' },
          '80%': { transform: 'translateX(8px)' },
        }
      }}>
        {/* Icon */}
        <Box sx={{
          width: 64, height: 64, borderRadius: 3, mx: 'auto', mb: 2.5,
          background: `linear-gradient(135deg, ${G.fern} 0%, ${G.forest} 100%)`,
          display: 'flex', alignItems: 'center', justifyContent: 'center',
          boxShadow: `0 0 30px rgba(71,133,89,0.4)`,
          border: '1px solid rgba(148,204,171,0.2)',
        }}>
          {locked
            ? <ShieldIcon sx={{ color: '#f87171', fontSize: 30 }} />
            : <LockIcon sx={{ color: G.mint, fontSize: 30 }} />}
        </Box>

        <Typography variant="h5" fontWeight={800} sx={{ color: G.foam, mb: 0.5 }}>
          Financial
        </Typography>
        <Typography sx={{ color: G.sage, fontSize: '0.85rem', mb: 3.5 }}>
          {locked ? `Locked — try again in ${lockTimer}s` : 'Enter your 4-digit PIN to access'}
        </Typography>

        {/* PIN dots */}
        <Box sx={{ display: 'flex', justifyContent: 'center', gap: 2, mb: 3 }}>
          {[0,1,2,3].map(i => (
            <Box key={i} sx={{
              width: 18, height: 18, borderRadius: '50%',
              border: `2px solid ${pin.length > i ? G.mint : 'rgba(148,204,171,0.3)'}`,
              bgcolor: pin.length > i ? G.mint : 'transparent',
              transition: 'all 0.15s',
              boxShadow: pin.length > i ? `0 0 8px ${G.mint}` : 'none',
            }} />
          ))}
        </Box>

        {error && (
          <Alert severity="error" sx={{ mb: 2.5, bgcolor: 'rgba(100,20,20,0.5)', color: '#f87171', border: '1px solid rgba(248,113,113,0.25)', fontSize: '0.82rem', py: 0.5 }}>
            {error}
          </Alert>
        )}

        {/* Numpad */}
        <Box sx={{ display: 'grid', gridTemplateColumns: 'repeat(3,1fr)', gap: 1.2 }}>
          {[1,2,3,4,5,6,7,8,9,'',0,'⌫'].map((k, i) => (
            <Box key={i} onClick={() => { if (k === '') return; if (k === '⌫') del(); else addDigit(String(k)); }}
              sx={{
                py: 1.8, borderRadius: 2.5, textAlign: 'center',
                cursor: k === '' || locked ? 'default' : 'pointer',
                bgcolor: k === '' ? 'transparent' : 'rgba(71,133,89,0.1)',
                border: `1px solid ${k === '' ? 'transparent' : 'rgba(148,204,171,0.15)'}`,
                color: k === '⌫' ? G.sage : G.foam,
                fontWeight: 700, fontSize: '1.2rem', lineHeight: 1,
                opacity: locked && k !== '' ? 0.4 : 1,
                transition: 'all 0.15s',
                '&:hover': k !== '' && !locked ? {
                  bgcolor: 'rgba(71,133,89,0.25)',
                  borderColor: 'rgba(148,204,171,0.35)',
                  transform: 'scale(1.05)',
                } : {},
                userSelect: 'none',
              }}>{k}</Box>
          ))}
        </Box>
      </Box>
    </Box>
  );
}


const CATEGORIES = {
  income: ['Salary', 'Freelance', 'Investment', 'Business', 'Gift', 'Other Income'],
  expense: ['Rent/Housing', 'Food & Groceries', 'Transport', 'Utilities', 'Entertainment', 'Health', 'Clothing', 'Education', 'Subscriptions', 'Other Expense']
};

const BUDGET_TIPS = [
  { rule: "50/30/20 Rule", desc: "50% needs (rent, food, bills) · 30% wants (fun, dining out) · 20% savings & investments", icon: "🎯" },
  { rule: "Pay Yourself First", desc: "Transfer your savings the same day you get paid — before you can spend it. Even $50/month becomes $600/year.", icon: "💰" },
  { rule: "Track Every Dollar", desc: "People who track spending save 15–20% more on average. You can't manage what you don't measure.", icon: "📊" },
  { rule: "Emergency Fund First", desc: "Build 3–6 months of expenses in a separate account before investing. This is your financial seatbelt.", icon: "🛡️" },
];

export default function Financial() {
  const [unlocked, setUnlocked] = useState(false);
  if (!unlocked) return <PinLock onUnlock={() => setUnlocked(true)} />;
  return <FinancialContent />;
}

function FinancialContent() {
  const [tab, setTab] = useState(0);
  const [transactions, setTransactions] = useState([
    { id: 1, type: 'income', amount: 3200, category: 'Salary', note: 'Monthly salary', date: new Date().toISOString().split('T')[0] },
    { id: 2, type: 'expense', amount: 1200, category: 'Rent/Housing', note: 'Monthly rent', date: new Date().toISOString().split('T')[0] },
    { id: 3, type: 'expense', amount: 180, category: 'Food & Groceries', note: 'Weekly groceries', date: new Date().toISOString().split('T')[0] },
  ]);
  const [cardLinked, setCardLinked] = useState(false);
  const [cardForm, setCardForm] = useState({ cardNumber: '', name: '', expiry: '', cvv: '' });
  const [cardError, setCardError] = useState('');
  const [cardSuccess, setCardSuccess] = useState(false);
  const [newTx, setNewTx] = useState({ type: 'expense', amount: '', category: '', note: '' });
  const [budgets, setBudgets] = useState({
    'Rent/Housing': 1200,
    'Food & Groceries': 400,
    'Transport': 200,
    'Entertainment': 150,
    'Subscriptions': 80,
  });
  const [editingBudget, setEditingBudget] = useState({});

  const totalIncome = transactions.filter(t => t.type === 'income').reduce((s, t) => s + t.amount, 0);
  const totalExpense = transactions.filter(t => t.type === 'expense').reduce((s, t) => s + t.amount, 0);
  const netBalance = totalIncome - totalExpense;
  const savingsRate = totalIncome > 0 ? Math.round(((totalIncome - totalExpense) / totalIncome) * 100) : 0;

  const expenseByCategory = transactions
    .filter(t => t.type === 'expense')
    .reduce((acc, t) => {
      acc[t.category] = (acc[t.category] || 0) + t.amount;
      return acc;
    }, {});

  const addTransaction = () => {
    if (!newTx.amount || !newTx.category) return;
    setTransactions([...transactions, {
      id: Date.now(),
      ...newTx,
      amount: parseFloat(newTx.amount),
      date: new Date().toISOString().split('T')[0]
    }]);
    setNewTx({ type: 'expense', amount: '', category: '', note: '' });
  };

  const deleteTransaction = (id) => setTransactions(transactions.filter(t => t.id !== id));

  const formatCardNumber = (val) => {
    const digits = val.replace(/\D/g, '').slice(0, 16);
    return digits.replace(/(.{4})/g, '$1 ').trim();
  };

  const formatExpiry = (val) => {
    const digits = val.replace(/\D/g, '').slice(0, 4);
    if (digits.length > 2) return `${digits.slice(0, 2)}/${digits.slice(2)}`;
    return digits;
  };

  const handleLinkCard = () => {
    const digits = cardForm.cardNumber.replace(/\s/g, '');
    if (digits.length < 15) { setCardError('Please enter a valid card number'); return; }
    if (!cardForm.name.trim()) { setCardError('Name on card is required'); return; }
    if (cardForm.expiry.length < 5) { setCardError('Please enter a valid expiry date'); return; }
    if (cardForm.cvv.length < 3) { setCardError('CVV must be 3–4 digits'); return; }
    setCardError('');
    setCardSuccess(true);
    setCardLinked(true);
    // Simulate auto-importing 3 recent transactions
    setTimeout(() => {
      setTransactions(prev => [
        ...prev,
        { id: Date.now() + 1, type: 'expense', amount: 45.99, category: 'Subscriptions', note: '🔄 Auto-imported: Netflix, Spotify', date: new Date().toISOString().split('T')[0] },
        { id: Date.now() + 2, type: 'expense', amount: 67.30, category: 'Food & Groceries', note: '🔄 Auto-imported: Grocery store', date: new Date().toISOString().split('T')[0] },
        { id: Date.now() + 3, type: 'income', amount: 250, category: 'Freelance', note: '🔄 Auto-imported: Freelance payment', date: new Date().toISOString().split('T')[0] },
      ]);
    }, 1500);
  };

  const inputSx = {
    '& .MuiOutlinedInput-root': {
      bgcolor: 'rgba(71,133,89,0.08)', color: G.foam,
      '& fieldset': { borderColor: 'rgba(71,133,89,0.18)' },
      '&:hover fieldset': { borderColor: 'G.textMid' },
      '&.Mui-focused fieldset': { borderColor: G.sage },
    },
    '& .MuiInputLabel-root': { color: 'G.textLight' },
    '& .MuiInputLabel-root.Mui-focused': { color: G.sage },
  };

  return (
    <Container maxWidth="lg" sx={{ py: 4 }}>
      <Box sx={{ mb: 4 }}>
        <Typography variant="h4" fontWeight={700} sx={{ color: G.foam }}>
          💳 Financial
        </Typography>
        <Typography variant="body2" sx={{ color: 'G.textLight', mt: 0.5 }}>
          Link your card and track every dollar automatically
        </Typography>
      </Box>

      {/* Summary Cards */}
      <Box sx={{ display: 'flex', gap: 2, mb: 4, flexWrap: 'wrap' }}>
        {[
          { label: 'Total Income', value: `$${totalIncome.toLocaleString()}`, color: G.mid, icon: <TrendingUpIcon /> },
          { label: 'Total Expenses', value: `$${totalExpense.toLocaleString()}`, color: '#ef4444', icon: <TrendingDownIcon /> },
          { label: 'Net Balance', value: `$${netBalance.toLocaleString()}`, color: netBalance >= 0 ? G.mid : '#ef4444', icon: <AccountBalanceIcon /> },
          { label: 'Savings Rate', value: `${savingsRate}%`, color: savingsRate >= 20 ? G.mid : savingsRate >= 10 ? '#f59e0b' : '#ef4444', icon: <TrendingUpIcon /> },
        ].map((item) => (
          <Box key={item.label} sx={{ flex: 1, minWidth: 160, bgcolor: 'rgba(71,133,89,0.12)', border: '1px solid rgba(71,133,89,0.08)', borderRadius: 2, p: 2.5 }}>
            <Box sx={{ display: 'flex', alignItems: 'center', gap: 1, mb: 1, color: item.color }}>
              {item.icon}
              <Typography variant="caption" sx={{ color: 'G.textLight', textTransform: 'uppercase', letterSpacing: 1 }}>
                {item.label}
              </Typography>
            </Box>
            <Typography variant="h5" fontWeight={700} sx={{ color: item.color }}>{item.value}</Typography>
          </Box>
        ))}
      </Box>

      {/* Tabs */}
      <Box sx={{ borderBottom: '1px solid rgba(71,133,89,0.08)', mb: 3 }}>
        <Tabs
          value={tab}
          onChange={(_, v) => setTab(v)}
          sx={{ '& .MuiTab-root': { color: 'G.textLight', textTransform: 'none', fontWeight: 600 }, '& .Mui-selected': { color: G.sage }, '& .MuiTabs-indicator': { bgcolor: G.sage } }}
        >
          <Tab label="Transactions" />
          <Tab label="Link Card" />
          <Tab label="Budgets" />
          <Tab label="Tips" />
        </Tabs>
      </Box>

      {/* TRANSACTIONS TAB */}
      {tab === 0 && (
        <Box>
          {/* Add Transaction */}
          <Card sx={{ bgcolor: 'rgba(71,133,89,0.12)', border: '1px solid rgba(71,133,89,0.08)', borderRadius: 3, mb: 3 }}>
            <CardContent sx={{ p: 3 }}>
              <Typography variant="h6" fontWeight={700} sx={{ color: G.foam, mb: 2 }}>
                + Add Transaction
              </Typography>
              <Box sx={{ display: 'flex', gap: 1, mb: 2 }}>
                {['expense', 'income'].map((t) => (
                  <Chip
                    key={t}
                    label={t.charAt(0).toUpperCase() + t.slice(1)}
                    onClick={() => setNewTx({ ...newTx, type: t, category: '' })}
                    sx={{
                      cursor: 'pointer',
                      bgcolor: newTx.type === t ? (t === 'income' ? G.pine : '#7f1d1d') : 'rgba(71,133,89,0.08)',
                      color: newTx.type === t ? (t === 'income' ? G.mint : '#f87171') : 'G.textLight',
                      fontWeight: 700, border: `1px solid ${newTx.type === t ? 'currentColor' : 'rgba(71,133,89,0.18)'}`
                    }}
                  />
                ))}
              </Box>
              <Box sx={{ display: 'flex', gap: 2, flexWrap: 'wrap' }}>
                <TextField
                  label="Amount ($)"
                  type="number"
                  value={newTx.amount}
                  onChange={(e) => setNewTx({ ...newTx, amount: e.target.value })}
                  InputProps={{ startAdornment: <InputAdornment position="start"><Typography sx={{ color: 'G.textLight' }}>$</Typography></InputAdornment> }}
                  sx={{ ...inputSx, width: 140 }}
                />
                <TextField
                  select
                  label="Category"
                  value={newTx.category}
                  onChange={(e) => setNewTx({ ...newTx, category: e.target.value })}
                  SelectProps={{ native: true }}
                  sx={{ ...inputSx, minWidth: 200 }}
                >
                  <option value="">Select category</option>
                  {CATEGORIES[newTx.type].map(c => <option key={c} value={c}>{c}</option>)}
                </TextField>
                <TextField
                  label="Note (optional)"
                  value={newTx.note}
                  onChange={(e) => setNewTx({ ...newTx, note: e.target.value })}
                  sx={{ ...inputSx, flex: 1, minWidth: 180 }}
                />
                <Button
                  variant="contained"
                  onClick={addTransaction}
                  startIcon={<AddIcon />}
                  sx={{ bgcolor: G.pine, '&:hover': { bgcolor: G.fern }, textTransform: 'none', fontWeight: 600, alignSelf: 'center' }}
                >
                  Add
                </Button>
              </Box>
            </CardContent>
          </Card>

          {/* Transaction List */}
          <Card sx={{ bgcolor: 'rgba(71,133,89,0.12)', border: '1px solid rgba(71,133,89,0.08)', borderRadius: 3 }}>
            <CardContent sx={{ p: 0 }}>
              <Typography variant="h6" fontWeight={700} sx={{ color: G.foam, p: 3, pb: 1 }}>
                Recent Transactions {cardLinked && <Chip label="Card Synced" size="small" sx={{ bgcolor: G.pine, color: G.mint, ml: 1 }} />}
              </Typography>
              <List sx={{ p: 0 }}>
                {[...transactions].reverse().map((tx, i) => (
                  <React.Fragment key={tx.id}>
                    {i > 0 && <Divider sx={{ borderColor: 'rgba(71,133,89,0.08)' }} />}
                    <ListItem
                      secondaryAction={
                        <IconButton onClick={() => deleteTransaction(tx.id)} size="small" sx={{ color: 'G.textMid', '&:hover': { color: '#ef4444' } }}>
                          <DeleteIcon fontSize="small" />
                        </IconButton>
                      }
                      sx={{ px: 3, py: 1.5 }}
                    >
                      <Box sx={{ display: 'flex', alignItems: 'center', gap: 2, flex: 1 }}>
                        <Box sx={{
                          width: 40, height: 40, borderRadius: '50%',
                          bgcolor: tx.type === 'income' ? '#0f2b1a' : '#1c0f0f',
                          display: 'flex', alignItems: 'center', justifyContent: 'center'
                        }}>
                          {tx.type === 'income'
                            ? <TrendingUpIcon sx={{ color: G.mid, fontSize: 18 }} />
                            : <TrendingDownIcon sx={{ color: '#ef4444', fontSize: 18 }} />}
                        </Box>
                        <Box>
                          <Typography fontWeight={600} sx={{ color: G.foam }}>{tx.category}</Typography>
                          <Typography variant="caption" sx={{ color: 'G.textMid' }}>{tx.note} · {tx.date}</Typography>
                        </Box>
                        <Typography fontWeight={700} sx={{ ml: 'auto', mr: 4, color: tx.type === 'income' ? G.mid : '#ef4444' }}>
                          {tx.type === 'income' ? '+' : '-'}${tx.amount.toFixed(2)}
                        </Typography>
                      </Box>
                    </ListItem>
                  </React.Fragment>
                ))}
              </List>
            </CardContent>
          </Card>
        </Box>
      )}

      {/* LINK CARD TAB */}
      {tab === 1 && (
        <Box>
          {cardLinked ? (
            <Card sx={{ bgcolor: '#0f2b1a', border: '1px solid G.pine', borderRadius: 3 }}>
              <CardContent sx={{ p: 4, textAlign: 'center' }}>
                <CheckCircleIcon sx={{ fontSize: 64, color: G.mid, mb: 2 }} />
                <Typography variant="h5" fontWeight={700} sx={{ color: G.foam, mb: 1 }}>
                  Card Linked Successfully!
                </Typography>
                <Typography sx={{ color: 'G.textLight', mb: 1 }}>
                  Card ending in ···· {cardForm.cardNumber.replace(/\s/g, '').slice(-4)}
                </Typography>
                <Typography sx={{ color: 'G.textLight' }}>
                  Your transactions are now being tracked automatically. New transactions will appear in real-time.
                </Typography>
                <Button
                  variant="outlined"
                  sx={{ mt: 3, borderColor: 'rgba(71,133,89,0.18)', color: 'G.textLight', textTransform: 'none' }}
                  onClick={() => { setCardLinked(false); setCardSuccess(false); setCardForm({ cardNumber: '', name: '', expiry: '', cvv: '' }); }}
                >
                  Link a Different Card
                </Button>
              </CardContent>
            </Card>
          ) : (
            <Card sx={{ bgcolor: 'rgba(71,133,89,0.12)', border: '1px solid rgba(71,133,89,0.08)', borderRadius: 3 }}>
              <CardContent sx={{ p: 4 }}>
                <Box sx={{ display: 'flex', alignItems: 'center', gap: 2, mb: 3 }}>
                  <CreditCardIcon sx={{ color: G.sage, fontSize: 32 }} />
                  <Box>
                    <Typography variant="h5" fontWeight={700} sx={{ color: G.foam }}>
                      Link Your Card
                    </Typography>
                    <Typography variant="body2" sx={{ color: 'G.textLight' }}>
                      Transactions auto-import and categorize themselves
                    </Typography>
                  </Box>
                </Box>

                <Alert severity="info" sx={{ bgcolor: '#0c1929', color: G.foam, border: '1px solid G.pine', mb: 3, '& .MuiAlert-icon': { color: G.sage } }}>
                  <Box sx={{ display: 'flex', alignItems: 'center', gap: 1 }}>
                    <LockIcon sx={{ fontSize: 16 }} />
                    <Typography variant="body2">
                      Your card info is encrypted and stored locally. It's never shared with third parties.
                    </Typography>
                  </Box>
                </Alert>

                {cardError && (
                  <Alert severity="error" sx={{ mb: 2, bgcolor: '#1c0f0f', color: '#f87171', border: '1px solid #7f1d1d' }}>
                    {cardError}
                  </Alert>
                )}

                <Box sx={{ display: 'flex', flexDirection: 'column', gap: 2.5, maxWidth: 480 }}>
                  <TextField
                    label="Card Number"
                    value={cardForm.cardNumber}
                    onChange={(e) => setCardForm({ ...cardForm, cardNumber: formatCardNumber(e.target.value) })}
                    placeholder="1234 5678 9012 3456"
                    InputProps={{ startAdornment: <InputAdornment position="start"><CreditCardIcon sx={{ color: 'G.textMid', fontSize: 20 }} /></InputAdornment> }}
                    sx={inputSx}
                  />
                  <TextField
                    label="Name on Card"
                    value={cardForm.name}
                    onChange={(e) => setCardForm({ ...cardForm, name: e.target.value.toUpperCase() })}
                    placeholder="JOHN DOE"
                    sx={inputSx}
                  />
                  <Box sx={{ display: 'flex', gap: 2 }}>
                    <TextField
                      label="Expiry Date"
                      value={cardForm.expiry}
                      onChange={(e) => setCardForm({ ...cardForm, expiry: formatExpiry(e.target.value) })}
                      placeholder="MM/YY"
                      sx={{ ...inputSx, flex: 1 }}
                    />
                    <TextField
                      label="CVV"
                      value={cardForm.cvv}
                      onChange={(e) => setCardForm({ ...cardForm, cvv: e.target.value.replace(/\D/g, '').slice(0, 4) })}
                      placeholder="123"
                      type="password"
                      sx={{ ...inputSx, width: 120 }}
                    />
                  </Box>
                  <Button
                    variant="contained"
                    onClick={handleLinkCard}
                    fullWidth
                    startIcon={<LockIcon />}
                    sx={{ bgcolor: G.pine, '&:hover': { bgcolor: G.fern }, textTransform: 'none', fontWeight: 700, py: 1.5 }}
                  >
                    Link Card Securely
                  </Button>
                </Box>

                <Box sx={{ mt: 3 }}>
                  <Typography variant="body2" fontWeight={600} sx={{ color: G.foam, mb: 1.5 }}>
                    What happens after linking:
                  </Typography>
                  {[
                    "Transactions import automatically — you see them in real-time",
                    "AI auto-categorizes each transaction (groceries, bills, etc.)",
                    "Budget alerts notify you when you're 80% through any category",
                    "Monthly summary report generated every 1st of the month"
                  ].map((item, i) => (
                    <Box key={i} sx={{ display: 'flex', gap: 1.5, mb: 1 }}>
                      <CheckCircleIcon sx={{ color: G.mid, fontSize: 16, mt: 0.3 }} />
                      <Typography variant="body2" sx={{ color: 'G.textLight' }}>{item}</Typography>
                    </Box>
                  ))}
                </Box>
              </CardContent>
            </Card>
          )}
        </Box>
      )}

      {/* BUDGETS TAB */}
      {tab === 2 && (
        <Box>
          <Typography variant="body2" sx={{ color: 'G.textLight', mb: 3 }}>
            Set spending limits per category. You'll get alerted at 80% and 100%.
          </Typography>
          {Object.keys(budgets).map((cat) => {
            const spent = expenseByCategory[cat] || 0;
            const limit = budgets[cat];
            const pct = Math.min((spent / limit) * 100, 100);
            const color = pct >= 100 ? '#ef4444' : pct >= 80 ? '#f59e0b' : G.mid;
            return (
              <Card key={cat} sx={{ bgcolor: 'rgba(71,133,89,0.12)', border: '1px solid rgba(71,133,89,0.08)', borderRadius: 2, mb: 2 }}>
                <CardContent sx={{ p: 2.5 }}>
                  <Box sx={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', mb: 1 }}>
                    <Typography fontWeight={600} sx={{ color: G.foam }}>{cat}</Typography>
                    <Box sx={{ display: 'flex', alignItems: 'center', gap: 1 }}>
                      <Typography variant="body2" sx={{ color: color, fontWeight: 700 }}>
                        ${spent.toFixed(0)} / ${limit}
                      </Typography>
                      {pct >= 100 && <Chip label="Over Budget!" size="small" sx={{ bgcolor: '#7f1d1d', color: '#f87171', fontSize: '0.65rem' }} />}
                      {pct >= 80 && pct < 100 && <Chip label="Almost at limit" size="small" sx={{ bgcolor: '#78350f', color: '#fcd34d', fontSize: '0.65rem' }} />}
                    </Box>
                  </Box>
                  <LinearProgress variant="determinate" value={pct} sx={{ height: 8, borderRadius: 4, bgcolor: 'rgba(71,133,89,0.08)', mb: 1.5, '& .MuiLinearProgress-bar': { bgcolor: color } }} />
                  <Box sx={{ display: 'flex', gap: 1, alignItems: 'center' }}>
                    <TextField
                      type="number"
                      size="small"
                      value={editingBudget[cat] !== undefined ? editingBudget[cat] : limit}
                      onChange={(e) => setEditingBudget({ ...editingBudget, [cat]: e.target.value })}
                      sx={{ ...inputSx, width: 120 }}
                      InputProps={{ startAdornment: <InputAdornment position="start"><Typography sx={{ color: 'G.textLight', fontSize: 12 }}>$</Typography></InputAdornment> }}
                    />
                    <Button
                      size="small"
                      onClick={() => {
                        if (editingBudget[cat]) setBudgets({ ...budgets, [cat]: parseFloat(editingBudget[cat]) });
                        setEditingBudget({ ...editingBudget, [cat]: undefined });
                      }}
                      sx={{ bgcolor: G.pine, color: G.foam, textTransform: 'none', '&:hover': { bgcolor: G.fern } }}
                    >
                      Save
                    </Button>
                  </Box>
                </CardContent>
              </Card>
            );
          })}
        </Box>
      )}

      {/* TIPS TAB */}
      {tab === 3 && (
        <Box>
          <Typography variant="body2" sx={{ color: 'G.textLight', mb: 3 }}>
            Rules that wealthy people actually follow — not theory, but actionable.
          </Typography>
          {BUDGET_TIPS.map((tip, i) => (
            <Card key={i} sx={{ bgcolor: 'rgba(71,133,89,0.12)', border: '1px solid rgba(71,133,89,0.08)', borderRadius: 3, mb: 2 }}>
              <CardContent sx={{ p: 3 }}>
                <Box sx={{ display: 'flex', gap: 2, alignItems: 'flex-start' }}>
                  <Typography variant="h3" component="span">{tip.icon}</Typography>
                  <Box>
                    <Typography variant="h6" fontWeight={700} sx={{ color: G.foam, mb: 0.5 }}>{tip.rule}</Typography>
                    <Typography sx={{ color: 'G.textLight', lineHeight: 1.7 }}>{tip.desc}</Typography>
                  </Box>
                </Box>
              </CardContent>
            </Card>
          ))}
        </Box>
      )}
    </Container>
  );
}
